1. using System.Collections.Concurrent;
2. using System.Collections.Frozen;
3. 
4. namespace Textualizer.Localisation;
5. 
6. /// <summary>
7. /// Defines the contract for formatting date/time humanization output
8. /// in a locale-specific manner.
9. /// </summary>
10. public interface IFormatter
11. {
12.     /// <summary>Formats a "just now" reference.</summary>
13.     string DateHumanize_Now();
14. 
15.     /// <summary>Formats a "never" reference.</summary>
16.     string DateHumanize_Never();
17. 
18.     /// <summary>Formats a time unit reference (e.g., "2 hours ago").</summary>
19.     string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false);
20. }
21. 
22. /// <summary>
23. /// Defines the contract for ordinalizing numbers in a locale-specific manner.
24. /// </summary>
25. public interface IOrdinalizer
26. {
27.     /// <summary>
28.     /// Converts a number to its ordinal string representation (e.g., 1 → "1st").
29.     /// </summary>
30.     string Convert(int number, string numberString);
31. }
32. 
33. /// <summary>
34. /// Defines the contract for providing date-to-ordinal-words conversion.
35. /// </summary>
36. public interface IDateToOrdinalWordsConverter
37. {
38.     /// <summary>Converts a date to its ordinal words representation.</summary>
39.     string Convert(DateTime date);
40. }
41. 
42. // --- Unsealed classes (the anti-pattern) ---
43. // In Humanizer, ~185 of 186 non-abstract, non-static classes are unsealed.
44. // JIT cannot devirtualize virtual/interface calls or optimize type checks
45. // without the sealed keyword.
46. 
47. /// <summary>
48. /// Default implementation of <see cref="IFormatter"/> providing English date/time formatting.
49. /// </summary>
50. public sealed class DefaultFormatter : IFormatter
51. {
52.     // Pre-computed lowercased unit names avoid Enum.ToString() + ToLowerInvariant()
53.     // allocations on every call.
54.     private static readonly FrozenDictionary<TimeUnit, string> s_singularUnits =
55.         new Dictionary<TimeUnit, string>
56.         {
57.             [TimeUnit.Second] = "second",
58.             [TimeUnit.Minute] = "minute",
59.             [TimeUnit.Hour] = "hour",
60.             [TimeUnit.Day] = "day",
61.             [TimeUnit.Month] = "month",
62.             [TimeUnit.Year] = "year",
63.         }.ToFrozenDictionary();
64. 
65.     private static readonly FrozenDictionary<TimeUnit, string> s_pluralUnits =
66.         new Dictionary<TimeUnit, string>
67.         {
68.             [TimeUnit.Second] = "seconds",
69.             [TimeUnit.Minute] = "minutes",
70.             [TimeUnit.Hour] = "hours",
71.             [TimeUnit.Day] = "days",
72.             [TimeUnit.Month] = "months",
73.             [TimeUnit.Year] = "years",
74.         }.ToFrozenDictionary();
75. 
76.     /// <inheritdoc />
77.     public string DateHumanize_Now() => "now";
78. 
79.     /// <inheritdoc />
80.     public string DateHumanize_Never() => "never";
81. 
82.     /// <inheritdoc />
83.     public string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false)
84.     {
85.         var units = count == 1 ? s_singularUnits : s_pluralUnits;
86.         var unit = units.TryGetValue(timeUnit, out var cached)
87.             ? cached
88.             : timeUnit.ToString().ToLowerInvariant();
89. 
90.         return toWords
91.             ? string.Concat(NumberToWords(count), " ", unit)
92.             : string.Concat(count.ToString(), " ", unit);
93.     }
94. 
95.     private static string NumberToWords(int number) =>
96.         number switch
97.         {
98.             1 => "one",
99.             2 => "two",
100.             3 => "three",
101.             _ => number.ToString()
102.         };
103. }
104. 
105. /// <summary>
106. /// German-specific formatter providing localized date/time humanization.
107. /// </summary>
108. public sealed class GermanFormatter : IFormatter
109. {
110.     /// <inheritdoc />
111.     public string DateHumanize_Now() => "jetzt";
112. 
113.     /// <inheritdoc />
114.     public string DateHumanize_Never() => "nie";
115. 
116.     /// <inheritdoc />
117.     public string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false)
118.     {
119.         var unit = GetGermanUnit(timeUnit, count);
120.         return $"{count} {unit}";
121.     }
122. 
123.     private static string GetGermanUnit(TimeUnit timeUnit, int count) =>
124.         (timeUnit, count) switch
125.         {
126.             (TimeUnit.Year, 1) => "Jahr",
127.             (TimeUnit.Year, _) => "Jahre",
128.             (TimeUnit.Month, 1) => "Monat",
129.             (TimeUnit.Month, _) => "Monate",
130.             (TimeUnit.Day, 1) => "Tag",
131.             (TimeUnit.Day, _) => "Tage",
132.             (TimeUnit.Hour, 1) => "Stunde",
133.             (TimeUnit.Hour, _) => "Stunden",
134.             (TimeUnit.Minute, 1) => "Minute",
135.             (TimeUnit.Minute, _) => "Minuten",
136.             (TimeUnit.Second, 1) => "Sekunde",
137.             (TimeUnit.Second, _) => "Sekunden",
138.             _ => timeUnit.ToString()
139.         };
140. }
141. 
142. /// <summary>
143. /// French-specific formatter providing localized date/time humanization.
144. /// </summary>
145. public sealed class FrenchFormatter : IFormatter
146. {
147.     /// <inheritdoc />
148.     public string DateHumanize_Now() => "maintenant";
149. 
150.     /// <inheritdoc />
151.     public string DateHumanize_Never() => "jamais";
152. 
153.     /// <inheritdoc />
154.     public string TimeUnitHumanize(TimeUnit timeUnit, int count, bool toWords = false)
155.     {
156.         var unit = GetFrenchUnit(timeUnit, count);
157.         return $"{count} {unit}";
158.     }
159. 
160.     private static string GetFrenchUnit(TimeUnit timeUnit, int count) =>
161.         (timeUnit, count) switch
162.         {
163.             (TimeUnit.Year, 1) => "an",
164.             (TimeUnit.Year, _) => "ans",
165.             (TimeUnit.Month, _) => "mois",
166.             (TimeUnit.Day, 1) => "jour",
167.             (TimeUnit.Day, _) => "jours",
168.             (TimeUnit.Hour, 1) => "heure",
169.             (TimeUnit.Hour, _) => "heures",
170.             (TimeUnit.Minute, 1) => "minute",
171.             (TimeUnit.Minute, _) => "minutes",
172.             (TimeUnit.Second, 1) => "seconde",
173.             (TimeUnit.Second, _) => "secondes",
174.             _ => timeUnit.ToString()
175.         };
176. }
