178. /// <summary>
179. /// Default ordinalizer providing English ordinal suffixes (1st, 2nd, 3rd, etc.).
180. /// </summary>
181. public class DefaultOrdinalizer : IOrdinalizer
182. {
183.     /// <inheritdoc />
184.     public virtual string Convert(int number, string numberString)
185.     {
186.         var suffix = (number % 100) switch
187.         {
188.             11 or 12 or 13 => "th",
189.             _ => (number % 10) switch
190.             {
191.                 1 => "st",
192.                 2 => "nd",
193.                 3 => "rd",
194.                 _ => "th"
195.             }
196.         };
197. 
198.         return numberString + suffix;
199.     }
200. }
201. 
202. /// <summary>
203. /// Spanish ordinalizer providing locale-specific ordinal formatting.
204. /// </summary>
205. public sealed class SpanishOrdinalizer : DefaultOrdinalizer
206. {
207.     /// <inheritdoc />
208.     public override string Convert(int number, string numberString) =>
209.         numberString + ".º";
210. }
211. 
212. /// <summary>
213. /// Italian ordinalizer providing locale-specific ordinal formatting.
214. /// </summary>
215. public sealed class ItalianOrdinalizer : DefaultOrdinalizer
216. {
217.     /// <inheritdoc />
218.     public override string Convert(int number, string numberString) =>
219.         numberString + "°";
220. }
221. 
222. /// <summary>
223. /// Romanian ordinalizer providing locale-specific ordinal formatting.
224. /// </summary>
225. public sealed class RomanianOrdinalizer : DefaultOrdinalizer
226. {
227.     /// <inheritdoc />
228.     public override string Convert(int number, string numberString)
229.     {
230.         // Complex Romanian ordinal logic
231.         if (number < 0)
232.         {
233.             return numberString;
234.         }
235. 
236.         return (number % 100) switch
237.         {
238.             1 => "primul",
239.             2 => "al doilea",
240.             _ => $"al {numberString}-lea"
241.         };
242.     }
243. }
