     private static readonly FrozenDictionary<TimeUnit, string> s_singularUnits =
         new Dictionary<TimeUnit, string>
         {
             [TimeUnit.Second] = "second",
             [TimeUnit.Minute] = "minute",
             [TimeUnit.Hour] = "hour",
             [TimeUnit.Day] = "day",
             [TimeUnit.Month] = "month",
             [TimeUnit.Year] = "year",
         }.ToFrozenDictionary();

     private static readonly FrozenDictionary<TimeUnit, string> s_pluralUnits =
         new Dictionary<TimeUnit, string>
         {
             [TimeUnit.Second] = "seconds",
             [TimeUnit.Minute] = "minutes",
             [TimeUnit.Hour] = "hours",
             [TimeUnit.Day] = "days",
             [TimeUnit.Month] = "months",
